#include<bits/stdc++.h>
using namespace std;
struct node
{
    double x,y;
    int id;
}a[1010],b[1010];
double dp[1010][1010][2];
int pre[1010][1010][2];
double dist(int i,int j)
{
    return sqrt(pow(a[i].x-a[j].x,2)+pow(a[i].y-a[j].y,2));
}
void print(int l,int r,int x)
{
    if(l==r)
    {
        printf("%d ",a[l].id);
        return;
    }
    if(x==0)
    {
        printf("%d ",a[l].id);
        print(l+1,r,pre[l][r][x]);
    }
    else
    {
        printf("%d ",a[r].id);
        print(l,r-1,pre[l][r][x]);
    }
}
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%lf%lf",&a[i].x,&a[i].y);
        a[i].id=i;
        b[i]=a[i];
    }
    int k=1;
    for(int i=2;i<=n;i++)
    {
        if(a[i].y>a[k].y)
        {
            k=i;
        }
    }
    for(int i=1;i<=k;i++)
    {
        a[i+n-k]=b[i];
    }
    for(int i=k+1;i<=n;i++)
    {
        a[i-k]=b[i];
    }
    for(int len=2;len<n;len++)
    {
        for(int l=1,r=len;r<n;l++,r++)
        {
            dp[l][r][0]=dp[l][r][1]=2e18;
            if(dp[l+1][r][0]+dist(l,l+1)<dp[l][r][0])
            {
                pre[l][r][0]=0;
                dp[l][r][0]=dp[l+1][r][0]+dist(l,l+1);
            }
            if(dp[l+1][r][1]+dist(l,r)<dp[l][r][0])
            {
                pre[l][r][0]=1;
                dp[l][r][0]=dp[l+1][r][1]+dist(l,r);
            }
            if(r>1&&dp[l][r-1][0]+dist(l,r)<dp[l][r][1])
            {
                pre[l][r][1]=0;
                dp[l][r][1]=dp[l][r-1][0]+dist(l,r);
            }
            if(r>1&&dp[l][r-1][1]+dist(r-1,r)<dp[l][r][1])
            {
                pre[l][r][1]=1;
                dp[l][r][1]=dp[l][r-1][1]+dist(r-1,r);
            }
        }
    }
    printf("%d ",a[n].id);
    if(dp[1][n-1][0]+dist(1,n)<dp[1][n-1][1]+dist(n-1,n))
    {
        print(1,n-1,0);
    }
    else
    {
        print(1,n-1,1);
    }
    return 0;
}
